class Solution:
    def diffWaysToParentheses(self, expression: str) -> list[str]:
        memo = {}

        def _diffWays(sub_expr):
            if sub_expr in memo:
                return memo[sub_expr]

            result = []
            is_numeric = True

            for i, char in enumerate(sub_expr):
                if char in "+-*":
                    is_numeric = False
                    left_parts = _diffWays(sub_expr[:i])
                    right_parts = _diffWays(sub_expr[i+1:])

                    for left in left_parts:
                        for right in right_parts:
                            result.append(f"({left}{char}{right})")

            if is_numeric:
                result.append(sub_expr)

            memo[sub_expr] = result
            return result

        return _diffWays(expression)
